// Simulate MLP neurons as binary detectors
const neurons = 8; // small MLP for visualization
const inputs = ['John kicked the ball', 'Mary gave a book', 'The ice melted slowly', 'He told her a secret'];

// Each input activates a different binary pattern
const patterns = [
  [1,0,1,1,0,0,1,0], // PROPEL pattern
  [1,1,0,0,1,0,0,1], // ATRANS pattern  
  [0,0,1,0,0,1,1,0], // STATE-CHANGE pattern
  [1,1,0,0,0,1,0,1], // MTRANS pattern
];

let html = '<div style="font-family:monospace;font-size:13px">';
html += '<b>MLP Neuron Activations (binary view):</b><br><br>';
inputs.forEach((inp, i) => {
  const bits = patterns[i].map(b => 
    `<span style="background:${b?'#4ade80':'#374151'};color:${b?'#000':'#666'};padding:2px 6px;margin:1px;border-radius:3px">${b}</span>`
  ).join('');
  html += `"${inp}"<br>${bits}<br><br>`;
});
html += '<i>Notice: similar event types activate similar bit patterns!</i></div>';
return html;

// Simulate the extraction pipeline
const events = [
  { text: 'kicked the ball', bits: [1,0,1,1,0,0,1,0], label: 'PROPEL' },
  { text: 'threw the rock',  bits: [1,0,1,1,0,0,1,0], label: 'PROPEL' },
  { text: 'gave her flowers', bits: [1,1,0,0,1,0,0,1], label: 'ATRANS' },
  { text: 'sold the car',    bits: [1,1,0,0,1,0,0,1], label: 'ATRANS' },
  { text: 'told a story',    bits: [1,1,0,0,0,1,0,1], label: 'MTRANS' },
  { text: 'taught physics',  bits: [1,1,0,0,0,1,0,1], label: 'MTRANS' },
  { text: 'punched him',     bits: [1,0,1,1,0,0,1,1], label: 'PROPEL+HARM' },
  { text: 'melted away',     bits: [0,0,1,0,0,1,1,0], label: 'STATE-Δ' },
];

// Cluster by Hamming similarity
const clusters = {};
events.forEach(e => {
  const key = e.bits.join('');
  if (!clusters[key]) clusters[key] = { bits: e.bits, events: [], label: e.label };
  clusters[key].events.push(e.text);
});

let html = '<div style="font-family:monospace;font-size:12px">';
html += '<b>Extracted Circuit Motifs:</b><br><br>';
Object.values(clusters).forEach(c => {
  const bitStr = c.bits.map(b => 
    `<span style="background:${b?'#60a5fa':'#1f2937'};color:${b?'#000':'#555'};padding:1px 4px;border-radius:2px">${b}</span>`
  ).join('');
  html += `<span style="color:#fbbf24">${c.label}</span>: ${bitStr}<br>`;
  html += `  └ ${c.events.join(', ')}<br><br>`;
});
html += '<i style="color:#a78bfa">Same bit pattern = same primitive operator!</i></div>';
return html;

// How many primitives fit in a Boolean feature space?
const features = ['has_agent', 'physical', 'transfer', 'mental', 'volitional'];
const K = features.length;
const total = Math.pow(2, K);

// Known primitives mapped to features
const primitives = [
  { name: 'ATRANS',  bits: [1,0,1,0,1], desc: 'abstract transfer (give, sell)' },
  { name: 'PTRANS',  bits: [1,1,1,0,1], desc: 'physical transfer (move, carry)' },
  { name: 'PROPEL',  bits: [1,1,0,0,1], desc: 'apply force (push, kick)' },
  { name: 'MTRANS',  bits: [1,0,1,1,1], desc: 'mental transfer (tell, teach)' },
  { name: 'MBUILD',  bits: [1,0,0,1,1], desc: 'mental build (decide, conclude)' },
  { name: 'INGEST',  bits: [1,1,0,0,1], desc: 'take in (eat, breathe)' },
  { name: 'EXPEL',   bits: [1,1,0,0,1], desc: 'push out (spit, exhale)' },
  { name: 'GRASP',   bits: [1,1,0,0,1], desc: 'grasp object (hold, release)' },
  { name: 'ATTEND',  bits: [1,0,0,1,0], desc: 'focus sense (look, listen)' },
  { name: 'SPEAK',   bits: [1,1,0,0,1], desc: 'produce sound' },
  { name: 'MOVE',    bits: [1,1,0,0,1], desc: 'move body part' },
];

let html = '<div style="font-family:monospace;font-size:12px">';
html += `<b>${K} binary features → ${total} possible combos, but only ${primitives.length} are occupied:</b><br><br>`;
html += '<table style="border-collapse:collapse">';
html += '<tr style="color:#fbbf24">' + ['Primitive', ...features.map(f=>f.slice(0,6))].map(h=>`<td style="padding:2px 6px;border-bottom:1px solid #444">${h}</td>`).join('') + '</tr>';
primitives.forEach(p => {
  html += '<tr>';
  html += `<td style="padding:2px 6px;color:#60a5fa">${p.name}</td>`;
  p.bits.forEach(b => {
    html += `<td style="padding:2px 6px;text-align:center;background:${b?'#166534':'#1c1917'};color:${b?'#4ade80':'#555'}">${b?'✓':'·'}</td>`;
  });
  html += '</tr>';
});
html += '</table><br>';
html += `<i style="color:#a78bfa">Occupancy: ${primitives.length}/${total} = ${(100*primitives.length/total).toFixed(1)}% of Boolean space</i></div>`;
return html;

// Explore how parameters affect primitive discovery
const configs = [
  { layers: '1-4', threshold: 0, minSupport: '5%', expected: 'Too few clusters (2-3): surface syntax, not semantics' },
  { layers: '8-12', threshold: 0, minSupport: '2%', expected: '10-15 clusters: SWEET SPOT — semantic primitives!' },
  { layers: '20-24', threshold: 0, minSupport: '1%', expected: 'Too many clusters (50+): task-specific, not primitive' },
  { layers: '8-12', threshold: 0.5, minSupport: '2%', expected: 'Fewer active neurons → cleaner but sparser patterns' },
];

let html = '<div style="font-family:monospace;font-size:12px">';
html += '<b>How extraction parameters affect results:</b><br><br>';
html += '<table style="border-collapse:collapse;width:100%">';
html += '<tr style="color:#fbbf24;border-bottom:1px solid #555">';
['Layers','Thresh','MinSup','Expected Result'].forEach(h => {
  html += `<td style="padding:4px 8px">${h}</td>`;
});
html += '</tr>';
configs.forEach((c,i) => {
  const bg = i===1 ? 'background:#1a3a1a' : '';
  html += `<tr style="${bg}">`;
  html += `<td style="padding:4px 8px;color:#60a5fa">${c.layers}</td>`;
  html += `<td style="padding:4px 8px">${c.threshold}</td>`;
  html += `<td style="padding:4px 8px">${c.minSupport}</td>`;
  html += `<td style="padding:4px 8px;color:${i===1?'#4ade80':'#ccc'}">${c.expected}</td>`;
  html += '</tr>';
});
html += '</table><br>';
html += '<i style="color:#a78bfa">🎯 Middle layers are where semantic primitives live — early layers handle syntax, late layers handle task specifics.</i></div>';
return html;
